(self.webpackChunkbeary_github_io=self.webpackChunkbeary_github_io||[]).push([[451],{360:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>e});const t=(0,a(987).uE)('<h1 id="选择符" tabindex="-1"><a class="header-anchor" href="#选择符" aria-hidden="true">#</a> 选择符</h1><h2 id="基本选择符" tabindex="-1"><a class="header-anchor" href="#基本选择符" aria-hidden="true">#</a> 基本选择符</h2><p><strong>类型（元素）选择符</strong> 选择制定类型的元素，<strong>后代选择符</strong> 选择某个或者某组元素的后代。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token comment">/* 类型(元素)选择符 */</span>\n<span class="token selector">p</span> <span class="token punctuation">{</span>\n  <span class="token property">color</span><span class="token punctuation">:</span> black<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token comment">/* 后代选择符 */</span>\n<span class="token selector">blockquote p</span> <span class="token punctuation">{</span>\n  <span class="token property">padding-left</span><span class="token punctuation">:</span> 2em<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>ID 选择符</strong> 和 <strong>类选择符</strong> 分别使用 <code>#</code> 和 <code>.</code> 开头。</p><h2 id="子选择符和同辈选择符" tabindex="-1"><a class="header-anchor" href="#子选择符和同辈选择符" aria-hidden="true">#</a> 子选择符和同辈选择符</h2><p>除了基本选择符， CSS 也提供了高级选择符，第一个高级选择符叫 <strong>子选择符</strong> ，它选择一个元素的直接后代。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>style</span><span class="token punctuation">&gt;</span></span><span class="token style"><span class="token language-css">\n<span class="token comment">/* 子选择符，使用 &gt; 表示 */</span>\n<span class="token selector">#nav &gt; li</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 样式 */</span>\n<span class="token punctuation">}</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>style</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ul</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>nav<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>被选择<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ul</span><span class="token punctuation">&gt;</span></span>\n      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>未选择<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>未选择<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>ul</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>被选择<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>ul</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p><strong>相邻同辈选择器</strong> 用于选择某个元素 <em>后面</em> 、并与该元素拥有相同父元素的元素。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>style</span><span class="token punctuation">&gt;</span></span><span class="token style"><span class="token language-css">\n<span class="token comment">/* 相邻同辈选择器，使用 + 号表示 */</span>\n<span class="token selector">h2 + p</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 样式 */</span>\n<span class="token punctuation">}</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>style</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>main</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（未被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h2</span><span class="token punctuation">&gt;</span></span>标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h2</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（未被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>main</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><code>&gt;</code> 和 <code>+</code> 被称为 <strong>组合子</strong> ，它描述自身两侧的组合方式。</p><p><code>~</code> 是 <strong>一般同辈组合子</strong> ，它与 <code>+</code> 类似，但选择的是同级后面的所有元素。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>style</span><span class="token punctuation">&gt;</span></span><span class="token style"><span class="token language-css">\n<span class="token comment">/* 相邻同辈选择器，使用 + 号表示 */</span>\n<span class="token selector">h2 ~ p</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 样式 */</span>\n<span class="token punctuation">}</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>style</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>main</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（未被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h2</span><span class="token punctuation">&gt;</span></span>标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h2</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>（被选择）段落<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>\n  ...\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>main</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="通用选择符" tabindex="-1"><a class="header-anchor" href="#通用选择符" aria-hidden="true">#</a> 通用选择符</h2><p><strong>通用选择符</strong> <code>*</code> 匹配任何元素。可以与组合子结合使用。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.production-section &gt; *</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 样式 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="属性选择符" tabindex="-1"><a class="header-anchor" href="#属性选择符" aria-hidden="true">#</a> 属性选择符</h2><p><strong>属性选择符</strong> 基于元素是否具有某个属性、或是属性是否具有某个值来选择元素。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">abbr[title]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择有 title 属性的 abbr 元素 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">abbr[title]:hover</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择有 title 属性的 abbr 元素鼠标悬浮状态 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">input[type=&quot;submit&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择有 type 属性为 submit 的 input 元素 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">a[href^=&quot;http:&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择 href 以 http: 开头的 a 标签 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">img[src$=&quot;.jpg&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择 src 以 .jpg 结尾的 img 标签 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">a[href*=&quot;/about/&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 选择 href 中包含 /about/ 的 a 标签 */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">a[ref~=&quot;next&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/*\n   * 选择 ref 中以空格分割后包含 next 的 a 标签\n   * 例如 &lt;a ref=&quot;aa next xx&quot;&gt;&lt;/a&gt;\n   */</span>\n<span class="token punctuation">}</span>\n<span class="token selector">a[lang|=&quot;en&quot;]</span> <span class="token punctuation">{</span>\n  <span class="token comment">/*\n   * 匹配指定值或指定值后连着短横线的情况，例如\n   * &lt;a lang=&quot;en&quot;&gt;&lt;/a&gt;\n   * &lt;a lang=&quot;en-us&quot;&gt;&lt;/a&gt;\n   */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br></div></div><h2 id="伪元素" tabindex="-1"><a class="header-anchor" href="#伪元素" aria-hidden="true">#</a> 伪元素</h2><p><code>::first-letter</code> 选择一段文本的第一个字符，如果要选择第一行，则用 <code>::first-line</code> 。</p><p>对应开头和结尾的假想元素，分别是 <code>::before</code> 和 <code>::after</code> 。通过 <code>content</code> 属性插入文本内容后，再像使用普通元素一样添加样式即可。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.chapter::before</span> <span class="token punctuation">{</span>\n  <span class="token property">content</span><span class="token punctuation">:</span> <span class="token string">&#39;;&#39;</span><span class="token punctuation">;</span> <span class="token comment">/* 插入文本内容 */</span>\n  <span class="token property">font-size</span><span class="token punctuation">:</span> 15em<span class="token punctuation">;</span> <span class="token comment">/* 其它属性 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="伪类" tabindex="-1"><a class="header-anchor" href="#伪类" aria-hidden="true">#</a> 伪类</h2><p>基于文档结构之外的情况为页面添加样式，比如基于超链接或表单元素的状态，就可以使用 <strong>伪类选择器</strong> 。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">a:link</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>\n<span class="token selector">a:visited</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>\n<span class="token selector">a:hover</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>\n<span class="token selector">a:focus</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>\n<span class="token selector">a:active</span> <span class="token punctuation">{</span> <span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="目标与反选" tabindex="-1"><a class="header-anchor" href="#目标与反选" aria-hidden="true">#</a> 目标与反选</h3><p>当访问浏览器地址栏 <code>https://xxx.com/path/to/page#comment-3</code> 时，地址栏的 hash 值为 <code>#comment-3</code> ，此时若页面中存在 <code>&lt;article class=&quot;comment&quot; id=&quot;comment-3&quot;&gt;...&lt;/article&gt;</code> ，那么通过下面的规则可以找到该条评论</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.comment:target</span> <span class="token punctuation">{</span>\n  <span class="token property">background-color</span><span class="token punctuation">:</span> #fffec4<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>其中 <code>.comment</code> 选择评论，然后 <code>target</code> 从地址中取到 <code>#comment-3</code> 并进行 ID 匹配。</p><p>使用 <code>:not()</code> 选择符可以排除某些选择符。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">.comment:target:not(.comment-downvoted)</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 和上面的选择器一样，但是如果存在 comment-downvoted 类则排除 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="结构化伪类" tabindex="-1"><a class="header-anchor" href="#结构化伪类" aria-hidden="true">#</a> 结构化伪类</h3><p><code>:nth-child()</code> 等，使用时看文档即可。</p><h3 id="表单伪类" tabindex="-1"><a class="header-anchor" href="#表单伪类" aria-hidden="true">#</a> 表单伪类</h3><p><code>input:required</code> 等，使用时看文档即可。</p><h2 id="层叠" tabindex="-1"><a class="header-anchor" href="#层叠" aria-hidden="true">#</a> 层叠</h2><p>当多条规则同时选择一个元素时， CSS 通过 <strong>层叠 (cascade)</strong> 的机制来处理冲突。</p><p>层叠机制的优先级从高到低</p><ul><li>标注 <code>!important</code> 的用户样式；</li><li>标注 <code>!important</code> 的作者样式；</li><li>作者样式；</li><li>用户样式；</li><li>浏览器（或用户代理）的默认样式；</li></ul><p>在此基础上，规则再按照选择符的特殊性排序。特殊性高的选择符覆盖特殊性低的选择符。若特殊性相等，后定义的规则优先。</p><h2 id="特殊性" tabindex="-1"><a class="header-anchor" href="#特殊性" aria-hidden="true">#</a> 特殊性</h2><p>特殊性的四个级别</p><ul><li>行内样式</li><li>ID 选择符</li><li>类选择符，伪类选择符，属性选择符</li><li>类型选择符，元素选择符</li></ul><p>其特殊性按照对于级别的的选择符数量相加。</p><p>比如</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">#id.class-1.class-2.p</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* 100 + 2 * 10 + 1 = 121 */</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="利用层叠次序" tabindex="-1"><a class="header-anchor" href="#利用层叠次序" aria-hidden="true">#</a> 利用层叠次序</h3><p>若两条规则特殊性相等，优先应用后定义的规则。</p><h3 id="控制特殊性" tabindex="-1"><a class="header-anchor" href="#控制特殊性" aria-hidden="true">#</a> 控制特殊性</h3><p>使用类选择符简化选择符、降低特殊性。</p><h2 id="继承" tabindex="-1"><a class="header-anchor" href="#继承" aria-hidden="true">#</a> 继承</h2><p>有些属性，比如颜色或文字大小，会被应用它们的元素的后代所继承。继承没有任何特殊性。</p><h2 id="为文档应用样式" tabindex="-1"><a class="header-anchor" href="#为文档应用样式" aria-hidden="true">#</a> 为文档应用样式</h2><h3 id="link-和-style-元素" tabindex="-1"><a class="header-anchor" href="#link-和-style-元素" aria-hidden="true">#</a> link 和 style 元素</h3><p>在 <code>head</code> 中添加 <code>style</code> 标签。</p><p>使用 <code>link</code> 元素。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>/css/base.css<span class="token punctuation">&quot;</span></span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>使用 <code>@import</code> 指令加载外部 CSS 文件。可以在 <code>head</code> 部分使用，也可以在外部样式中使用。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>style</span><span class="token punctuation">&gt;</span></span><span class="token style"><span class="token language-css">\n  <span class="token atrule"><span class="token rule">@import</span> <span class="token url"><span class="token function">url</span><span class="token punctuation">(</span><span class="token string url">&quot;/css/modules.css&quot;</span><span class="token punctuation">)</span></span><span class="token punctuation">;</span></span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>style</span><span class="token punctuation">&gt;</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>引入时要注意加载顺序，同样特殊性的规则下、最后加载的会生效。</p><h3 id="性能" tabindex="-1"><a class="header-anchor" href="#性能" aria-hidden="true">#</a> 性能</h3><p>CSS 应该放在 <code>head</code> 中，让浏览器尽可能早的下载全部 CSS 和 HTML 。</p><h4 id="减少-http-请求" tabindex="-1"><a class="header-anchor" href="#减少-http-请求" aria-hidden="true">#</a> 减少 HTTP 请求</h4><p>最好把 CSS 文件数量控制在一到两个，尽可能不要在生产环境使用 <code>@import</code> ，因为它会产生额外的 HTTP 请求。</p><h4 id="压缩和缓存内容" tabindex="-1"><a class="header-anchor" href="#压缩和缓存内容" aria-hidden="true">#</a> 压缩和缓存内容</h4><p>线上启用 GZIP 压缩 CSS ，一般来说 CSS 压缩后其文件大小能减少 70%~80% ，减少带宽占用。</p><p>通过 HTTP 头部告诉浏览器缓存文件，如果文件有修改，则通过文件名来 “清除缓存” （例如 webpack 的文件名 hash）。</p><h4 id="不让浏览器渲染阻塞-javascript" tabindex="-1"><a class="header-anchor" href="#不让浏览器渲染阻塞-javascript" aria-hidden="true">#</a> 不让浏览器渲染阻塞 JavaScript</h4><p>如果在 HTML 的 <code>&lt;head&gt;</code> 元素中加入了 <code>&lt;script&gt;</code> 元素，那么浏览器必须先把它链接的脚本下载下来，然后再显示网页内容。</p><p>主流的做法是在页面最底部的 <code>&lt;/body&gt;</code> 之前加载 JavaScript 。</p><p>比较现代的做法是在 <code>&lt;head&gt;</code> 中使用 <code>&lt;script&gt;</code> 标签，但添加 <code>async</code> 和 <code>defer</code> 属性。<code>defer</code> 会异步加载脚本，不阻塞 HTML 解析，但脚本加载完成时会立即执行、阻塞 HTML 解析。<code>defer</code> 会异步加载脚本，并且在 HTML 加载完毕之后再执行加载的脚本。</p>',72),e={render:function(n,s){return t}}},417:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>t});const t={key:"v-72386375",path:"/css/selector.html",title:"选择符",lang:"en-US",frontmatter:{title:"选择符"},excerpt:"",headers:[{level:2,title:"基本选择符",slug:"基本选择符",children:[]},{level:2,title:"子选择符和同辈选择符",slug:"子选择符和同辈选择符",children:[]},{level:2,title:"通用选择符",slug:"通用选择符",children:[]},{level:2,title:"属性选择符",slug:"属性选择符",children:[]},{level:2,title:"伪元素",slug:"伪元素",children:[]},{level:2,title:"伪类",slug:"伪类",children:[{level:3,title:"目标与反选",slug:"目标与反选",children:[]},{level:3,title:"结构化伪类",slug:"结构化伪类",children:[]},{level:3,title:"表单伪类",slug:"表单伪类",children:[]}]},{level:2,title:"层叠",slug:"层叠",children:[]},{level:2,title:"特殊性",slug:"特殊性",children:[{level:3,title:"利用层叠次序",slug:"利用层叠次序",children:[]},{level:3,title:"控制特殊性",slug:"控制特殊性",children:[]}]},{level:2,title:"继承",slug:"继承",children:[]},{level:2,title:"为文档应用样式",slug:"为文档应用样式",children:[{level:3,title:"link 和 style 元素",slug:"link-和-style-元素",children:[]},{level:3,title:"性能",slug:"性能",children:[]}]}],filePathRelative:"css/selector.md",git:{updatedTime:1626009975e3,contributors:[]}}}}]);